import type { NativeSyntheticEvent, NativeScrollEvent } from 'react-native';
import type { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import type { propsItemsListCardTransition } from '@semparar/design-system-app/src/atomic/organisms/ListCardTransition/Models';
import type {
  PointsExtractData,
  PaginationDto,
  AppliedFilters,
} from '../../../services/models';
export {
  TYPE_LABELS, PERIOD_DAYS_MAP
} from '../../../services/models';
export type {
  PointsExtractData,
  PaginationDto,
  AppliedFilters,
  TransactionType
} from '../../../services/models';

export interface FilterGroup {
  label: string;
  options: Array<{ label: string; value: number | string }>;
}

export interface ExtractRewardProgramParams {
  analytics?: {
    screen_name?: string;
    screen_class?: string;
    screen_bussines?: string;
    screen_info?: {
      location_1?: string;
      location_2?: string;
      location_3?: string;
    };
  };
}

export interface ExtractRewardProgramState {
  pointsAvailable: number;
  extractData?: PointsExtractData;
  pagination?: PaginationDto;
  isLoadingExtract: boolean;
  isLoadingMore: boolean;
  isLoadingBalance: boolean;
  hasError: boolean;
  appliedTransactionsFilters?: AppliedFilters;
  isRefreshing: boolean;
  transactionsData: propsItemsListCardTransition[];
  searchText: string;
  activeFiltersCount?: string;
  transactionsEmptyMessage: string;
  shouldShowTransactionsList: boolean;
  filterGroups: FilterGroup[];
  initialFilters: Record<number, unknown>;
  modalizeRefInfo: React.RefObject<PropsModalizeRef>;
  modalizeRefFilters: React.RefObject<PropsModalizeRef>;
}

export interface ExtractRewardProgramHandlers {
  handleGoBack: () => void;
  requestPointsExtract: () => void;
  handleLoadMore: () => void;
  setTransactionsFilters: (filters: AppliedFilters) => void;
  clearTransactionsFilters: () => void;
  handleSearchChange: (text: string) => void;
  handleRefresh: () => void;
  handleError: () => void;
  handleScroll: (event: NativeSyntheticEvent<NativeScrollEvent>) => void;
  handleIconInfoPress: () => void;
  handleFilterIconPress: () => void;
  handleApplyFilters: (filters: Record<number, unknown>) => void;
  handleTabChange: (index: number) => void;
  handleSearchPressIn: () => void;
}

export type UseExtractRewardProgramReturn = ExtractRewardProgramState &
  ExtractRewardProgramHandlers;

export interface ExtractRewardProgramProps {
  route?: {
    params?: ExtractRewardProgramParams;
  };
  navigation: {
    goBack: () => void;
  };
}

export interface EmptyListProps {
  label: string;
}

export interface TransactionsListProps {
  items: propsItemsListCardTransition[];
  isLoading: boolean;
}

